import uuid, redis, json
from fastapi import FastAPI

app = FastAPI()
r = redis.Redis(host="localhost", port=6379, decode_responses=True)

@app.post("/tasks")
def create_task(payload: dict):
    task_id = str(uuid.uuid4())
    r.hset(f"task:{task_id}", mapping={
        "status": "QUEUED",
        "payload": json.dumps(payload),
        "result": "",
    })
    # Push task_id onto the queue (separate Redis list used as simple queue)
    r.rpush("agent:queue", task_id)
    return {"task_id": task_id}

@app.get("/tasks/{task_id}")
def get_task(task_id: str):
    data = r.hgetall(f"task:{task_id}")
    if not data:
        return {"error": "not found"}, 404
    return {
        "task_id": task_id,
        "status": data["status"],
        "result": json.loads(data["result"]) if data["result"] else None,
    }

import time, json, redis, anthropic

r = redis.Redis(host="localhost", port=6379, decode_responses=True)
client = anthropic.Anthropic()

MAX_STEPS = 20

def run_agent(task_id: str, goal: str):
    r.hset(f"task:{task_id}", "status", "RUNNING")
    messages = [{"role": "user", "content": goal}]
    tools = [
        {"name": "web_search", "description": "Search the web",
         "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}},
    ]

    for step in range(MAX_STEPS):
        # Heartbeat: tell the state store the worker is alive
        r.hset(f"task:{task_id}", mapping={
            "heartbeat": str(time.time()),
            "step": str(step),
        })

        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            tools=tools,
            messages=messages,
        )

        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Agent is done
            final_text = next(
                (b.text for b in response.content if hasattr(b, "text")), ""
            )
            r.hset(f"task:{task_id}", mapping={
                "status": "DONE",
                "result": json.dumps({"answer": final_text}),
            })
            return

        # Process tool calls
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })

        messages.append({"role": "user", "content": tool_results})

    # Exceeded max steps
    r.hset(f"task:{task_id}", "status", "FAILED")

def dispatch_tool(name: str, inputs: dict) -> str:
    if name == "web_search":
        return f"Search results for: {inputs['query']} (placeholder)"
    return "unknown tool"

def worker_loop():
    print("Worker started — polling queue")
    while True:
        item = r.blpop("agent:queue", timeout=5)
        if item:
            _, task_id = item
            data = r.hgetall(f"task:{task_id}")
            payload = json.loads(data.get("payload", "{}"))
            try:
                run_agent(task_id, payload.get("goal", ""))
            except Exception as e:
                r.hset(f"task:{task_id}", mapping={"status": "FAILED", "error": str(e)})

if __name__ == "__main__":
    worker_loop()

import httpx

def notify_webhook(task_id: str, result: dict, webhook_url: str):
    """Call this at the end of run_agent instead of just setting status."""
    try:
        httpx.post(webhook_url, json={
            "task_id": task_id,
            "status": "DONE",
            "result": result,
        }, timeout=10)
    except Exception as e:
        # Webhook delivery failure must not crash the worker
        print(f"Webhook failed: {e}")

